struct run { struct run *next; uint64 npage; };
struct pm_allocator { struct spinlock lock; struct run *freelist; uint64 npage; };
struct pm_allocator multiple;
struct pm_allocator single;

void kpminit(void) {
    multiple.freelist = NULL; multiple.npage = 0;
    single.freelist = NULL; single.npage = 0;
    __mul_freerange((uint64)boot_stack_top, START_SINGLE);
    __sin_freerange(START_SINGLE, PHYSTOP);
}

uint64 _allocpage(void) {
    // try single first, then borrow from multiple
    struct run *ret;
    __enter_sin_cs ret = __sin_alloc_no_lock(); __leave_sin_cs
    if (NULL == ret) {
        __enter_mul_cs ret = __mul_alloc_no_lock(1); __leave_mul_cs
    }
    return (uint64)ret;
}

struct kmem_node {
    struct kmem_node *next;
    struct { uint64 obj_size; uint64 obj_addr; } config;
    uint8 avail; uint8 cnt;
    uint8 table[KMEM_OBJ_MAX_COUNT];
};
struct kmem_allocator {
    struct spinlock lock;
    uint obj_size; uint16 npages; uint16 nobjs;
    struct kmem_node *list;
    struct kmem_allocator *next;
};

void kmallocinit(void) { ... }
void *kmalloc(uint size) { ... }  // slab allocation
void kfree(void *addr) { ... }    // return to slab

pte_t * walk(pagetable_t pagetable, uint64 va, int alloc) {
    for(int level = 2; level > 0; level--) {
        pte_t *pte = &pagetable[PX(level, va)];
        if(*pte & PTE_V) {
            pagetable = (pagetable_t)PTE2PA(*pte);
        } else {
            if(!alloc || (pagetable = (pde_t*)allocpage()) == NULL)
                return NULL;
            memset(pagetable, 0, PGSIZE);
            *pte = PA2PTE(pagetable) | PTE_V;
        }
    }
    return &pagetable[PX(0, va)];
}

#define KERNBASE 		0x80020000UL

#define PHYSTOP                 0x80600000UL

// map the trampoline page to the highest address,
// in both user and kernel space.
#define TRAMPOLINE              (MAXVA - PGSIZE)

static void *__mul_alloc_no_lock(uint64 n) {
	struct run *pa;
	struct run **pprev;

	pa = multiple.freelist;
	pprev = &(multiple.freelist);

	while (NULL != pa) {
		if (pa->npage >= n) {
			struct run *ret = (struct run*)(
				(uint64)pa + PGSIZE * (pa->npage - n)
			);
			if (pa == ret) {
				*pprev = pa->next;
			}
			else {
				pa->npage -= n;
				pa = ret;
			}
			multiple.npage -= n;
			break;
		}
		pprev = &(pa->next);
		pa = pa->next;
	}
	return (void*)pa;
}

static void __mul_free_no_lock(uint64 start, uint64 n) {
	if (NULL == multiple.freelist) {
		multiple.freelist = (struct run*)start;
		multiple.freelist->npage = n;
		multiple.freelist->next = NULL;
		multiple.npage = n;
		return ;
	}
	struct run *prev = NULL;
	struct run *next = multiple.freelist;
	while (NULL != next) {
		if ((uint64)next > start) break;
		else { prev = next; next = next->next; }
	}
	struct run *pa = (struct run*)start;
	pa->next = next;
	pa->npage = n;
	// merge with previous
	if (NULL != prev) {
		if (((uint64)prev + prev->npage * PGSIZE) == (uint64)pa) {
			prev->npage += n; pa = prev;
		} else { prev->next = pa; }
	} else { multiple.freelist = pa; pa->npage = n; }
	// merge with next
	if (NULL != next) {
		if (((uint64)pa + pa->npage * PGSIZE) == (uint64)next) {
			pa->npage += next->npage; pa->next = next->next;
		}
	}
	multiple.npage += n;
}

int
mappages(pagetable_t pagetable, uint64 va, uint64 size, uint64 pa, int perm)
{
	uint64 a, last;
	pte_t *pte;

	a = PGROUNDDOWN(va);
	last = PGROUNDDOWN(va + size - 1);

	int usr = perm & PTE_U;
	for(;;){
		if((pte = walk(pagetable, a, 1)) == NULL)
			return -1;
		if (*pte & PTE_U) {
			__debug_assert("mappages", PTE2PA(*pte) == NULL, "invalid page with ppn\n");
			*pte |= PA2PTE(pa) | PTE_V;
		} else {
			*pte = PA2PTE(pa) | perm | PTE_V;
		}
		if (usr)
			pagedup(PGROUNDDOWN(pa));
		if(a == last)
			break;
		a += PGSIZE;
		pa += PGSIZE;
	}
	return 0;
}

