static void *__mul_alloc_no_lock(uint64 n) {
	struct run *pa;
	struct run **pprev;

	pa = multiple.freelist;
	pprev = &(multiple.freelist);

	while (NULL != pa) {
		if (pa->npage >= n) {
			struct run *ret = (struct run*)(
				(uint64)pa + PGSIZE * (pa->npage - n)
			);
			if (pa == ret) {
				*pprev = pa->next;
			}
			else {
				pa->npage -= n;
				pa = ret;
			}
			multiple.npage -= n;
			break;
		}
		pprev = &(pa->next);
		pa = pa->next;
	}
	return (void*)pa;
}

